import SwiftUI
import UIKit

final class PasswordResetRouter: ObservableObject {
    @Published var resetToken: String?
    
    func handleUniversalLink(_ url: URL) -> Bool {
        guard isPasswordResetURL(url) else { return false }
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false),
              let token = components.queryItems?.first(where: { $0.name == "token" })?.value,
              !token.isEmpty else {
            return false
        }
        DispatchQueue.main.async {
            self.resetToken = token
        }
        return true
    }
    
    private func isPasswordResetURL(_ url: URL) -> Bool {
        guard let host = url.host?.lowercased() else { return false }
        let normalizedPath = url.path.trimmingCharacters(in: CharacterSet(charactersIn: "/")).lowercased()
        return host == "myapp.com" && normalizedPath == "reset-password"
    }
    
    func clear() {
        resetToken = nil
    }
}

final class AppDelegate: NSObject, UIApplicationDelegate {
    var router: PasswordResetRouter?
    
    func application(_ application: UIApplication,
                     continue userActivity: NSUserActivity,
                     restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return false
        }
        return router?.handleUniversalLink(url) ?? false
    }
}

